import React, { useState } from "react";
import Header from "./Header";
import Sidebar from "./Sidebar";

// Exemplo de componente de conteúdo
function Dashboard() {
  return <div className="p-6 text-2xl font-bold">Bem-vindo ao Dashboard!</div>;
}
function AgendarPaciente() {
  return <div className="p-6 text-2xl font-bold">Formulário de Agendar Paciente</div>;
}
function Disciplinas() {
  return <div className="p-6 text-2xl font-bold">Gerenciar Disciplinas</div>;
}
function Pacientes() {
  return <div className="p-6 text-2xl font-bold">Lista de Pacientes</div>;
}
function Alunos() {
  return <div className="p-6 text-2xl font-bold">Lista de Alunos</div>;
}
function Solicitacoes() {
  return <div className="p-6 text-2xl font-bold">Solicitações</div>;
}
function Configuracoes() {
  return <div className="p-6 text-2xl font-bold">Configurações</div>;
}
function Ajuda() {
  return <div className="p-6 text-2xl font-bold">Central de Ajuda</div>;
}

export default function App() {
  const [active, setActive] = useState("dashboard");

  // Renderiza o conteúdo com base no menu ativo
  function renderContent() {
    switch (active) {
      case "dashboard":
        return <Dashboard />;
      case "agendar":
        return <AgendarPaciente />;
      case "disciplinas":
        return <Disciplinas />;
      case "pacientes":
        return <Pacientes />;
      case "alunos":
        return <Alunos />;
      case "solicitacoes":
        return <Solicitacoes />;
      case "configuracoes":
        return <Configuracoes />;
      case "ajuda":
        return <Ajuda />;
      default:
        return <Dashboard />;
    }
  }

  return (
    <div className="bg-[#F6F6F8] min-h-screen">
      {/* Header fixo no topo */}
      <Header />

      {/* Flex para Sidebar + Conteúdo */}
      <div className="flex">
        {/* Sidebar (começa logo abaixo do header, por isso mt-16) */}
        <Sidebar active={active} onMenuClick={setActive} />

        {/* Conteúdo principal */}
        <main
          className="flex-1 ml-64 mt-16 p-8"
          // ml-64: igual à largura do Sidebar, mt-16: altura do Header
        >
          <div className="max-w-6xl mx-auto">{renderContent()}</div>
        </main>
      </div>
    </div>
  );
}
